            rs2_set_option((const rs2_options*)sen, RS2_OPTION_VISUAL_PRESET, preset_index, NULL);
            done = 1;
            break;
        }
    }

    // store sen, delete on program exit
}

rs2_pipeline* pipe = rs2_create_pipeline(ctx, &e);
rs2_config* config = rs2_create_config(&e);
rs2_config_enable_stream(config, RS2_STREAM_DEPTH, -1, cDepthW, cDepthH, RS2_FORMAT_Z16, 30, NULL);
rs2_pipeline_profile* selection = rs2_pipeline_start_with_config(pipe, config, NULL);
```

