Now you can do:

```python
class SuperInterfaceOptions(InterfaceOptions):
    extra_option = None

class SuperInterface(Interface):
    class Meta:
        abstract = True

    @classmethod
    def __init_subclass_with_meta__(cls, extra_option=None, **options):
        meta = SuperInterfaceOptions(cls)
        meta.extra_option = extra_option
        return Interface.__init_subclass_with_meta__(cls, _meta=meta, **options)
```

